  /***
   * A class to implement n*m*l array for loop
   * ex: if depth in doLoop(depth) is 3, and lengthArray in constructor is [2, 1, 3]
   * then the result will be:
   * 0 0 0
   * 0 0 1
   * 0 0 2
   * 1 0 0
   * 1 0 1
   * 1 0 2
   * 6 results in total because 2*1*3 == 6
   */
  public interface NestedForLoopAction {
    void act(int[] indices, NestedForLoop nfl);
  }

  public class NestedForLoop {
    private final int lo;
    private final NestedForLoopAction action;
    private final List<Integer> lengthArray;
    private boolean ifTooLarge = false;

    NestedForLoop(int lo, NestedForLoopAction action, List<Integer> lengthArray) {
      this.lo = lo;
      this.action = action;
      this.lengthArray = lengthArray;
    }

    private void doLoop(int depth) throws Exception{
      if(depth > lengthArray.size()) throw new Exception("depth must be smaller than or equal to lengthArray's size");
      doLoop(0, new int[0], depth);
    }

    private void doLoop(int level, int[] indices, int maxLevel) {
      if (level == maxLevel) {
        action.act(indices, this);
      } else {
        int newLevel = level + 1;
        int[] newIndices = new int[newLevel];
        System.arraycopy(indices, 0, newIndices, 0, level);
        newIndices[level] = lo;
        while (newIndices[level] < lengthArray.get(level) && !ifTooLarge) {
          doLoop(newLevel, newIndices, maxLevel);
          ++newIndices[level];
        }
      }
    }

    boolean isIfTooLarge() {
      return ifTooLarge;
    }

    void setIfTooLarge(boolean ifTooLarge) {
      this.ifTooLarge = ifTooLarge;
    }
  }

  private String createNewFieldSelect(PivotReport.PivotTable pivotTable, PivotReport.PivotType pivotType, List<CellInfo> selectionFields, List<CellInfo> textFields, RagicBundle bundle, Set<Integer> involvedDomainIds) {
    StringBuilder _select = new StringBuilder();
    _select.append("<div class='pivotFields' draggable='true' ondrag='dragging(event)' ondragend=\\\"dragEnd(event, '" + pivotTable.getTableId() + "');\\\">");
    _select.append("<i class='fal fa-times closeIcon imageDel hide' onclick=\\\"deleteRowCol(event, '" + pivotType + "', '" + pivotTable.getTableId() + "');\\\"></i>");
    _select.append("<select onchange=\\\"_updateConfig('" + pivotType + "', this.options[this.selectedIndex].value, '-1', '" + pivotTable.getTableId() + "');\\\">");
    if(pivotType.equals(PivotReport.PivotType.ROW)) {
      _select.append("<option value='-1'>"+bundle.getString("chooseRowField")+"</option>");
    }
    else if(pivotType.equals(PivotReport.PivotType.COL)) {
      _select.append("<option value='-1'>"+bundle.getString("chooseColumnField")+"</option>");
    }
    for(CellInfo info : selectionFields) {
      int _domainId = info.getDomainId();
      if(!involvedDomainIds.contains(_domainId)) {
        _select.append("<option value='" + _domainId + "' >" + Encoder.doubleQuoteReplacement(info.getValue()) + "</option>");
      }
    }
    for(CellInfo info : textFields) {
      int _domainId = info.getDomainId();
      if(!involvedDomainIds.contains(_domainId)) {
        _select.append("<option value='" + _domainId + "' >" + Encoder.doubleQuoteReplacement(info.getValue()) + "</option>");
      }
    }
    _select.append("</select>");
    _select.append("</div>");

    return _select.toString();
  }

  private String formatDisplayValueAsPlainText(String value, CellInfo info, String apname, RagicBundle bundle){
    if(info != null && (info.getAttribute("fmt_n") != null || info.getAttribute("fmt_d") != null)) {
      CellInfoDisplayInfoRetriever retriever = new CellInfoDisplayInfoRetriever(info, value);
      return CellValueDisplayHelper.formatDisplayValueAsPlainText(retriever, apname, -1, bundle);
    }
    else {
      return value;
    }
  }

  private void collectKeys(List<String> keys, Map<String , String> valueToFilterValue, int i, int index, List<Selection> selections, List<Set<String>> sets, List<List<String>> values, Map<Integer, CategoryDate> categorys, List<Integer> domainIds, NUIForm form, String apname, RagicBundle bundle) {
    Selection selection = selections.get(i);
    Set<String> set = sets.get(i);
    String oriValue = values.get(i).get(index);
    String formattedValue = Encoder.textToHTML(oriValue);
    CategoryDate category = categorys.get(domainIds.get(i));
    String encodedValue, displayValue;

    //match cascaded selection values
    if(selection != null) {
      if (selection.isCascaded()) {
        if(set.stream().anyMatch(rowOption -> rowOption != null && rowOption.endsWith("|" + Encoder.contentDecode(oriValue)))) {
          formattedValue = oriValue;
        }
      }
      if (category != null) {
        try {
          formattedValue = category.categorize(formattedValue);
        } catch(Exception ex) {
          formattedValue = "";
        }
      }

      displayValue = formatDisplayValueAsPlainText(formattedValue, form.getField(domainIds.get(i)), apname, bundle);
      if (category != null) { //如果是日期的話，會有重複key的問題，因此把原始值設成格式化過後的值，然後搭配模糊搜尋
        encodedValue = formattedValue;  //日期要用 db 的格式: yyyy/MM/dd
        if(category.type == CategoryDate.QUARTER)
          encodedValue = "Q" + encodedValue;
        if(category.type == CategoryDate.WEEK)
          encodedValue = "W" + encodedValue;

        encodedValue = "_date_:" + encodedValue;
      }
      else {
        encodedValue = Encoder.encodeCustomJs(oriValue);
      }

      valueToFilterValue.put(displayValue,encodedValue);

//      if (!set.contains(displayValue)) set.add(displayValue);

      keys.add(displayValue.replaceAll("\\|","&#124;"));
    }
  }

